const topics = [
  { keyword: 'mental toughness for athletes', title: 'How to Build Mental Toughness as an Athlete' },
  { keyword: 'sports psychology techniques', title: '5 Sports Psychology Techniques Every Athlete Needs' },
  { keyword: 'pre competition anxiety', title: 'How to Overcome Pre-Competition Anxiety' },
  { keyword: 'athlete confidence building', title: 'The Science of Building Unshakable Athlete Confidence' },
  { keyword: 'flow state sports', title: 'How to Trigger Flow State Before Your Event' },
  { keyword: 'mental blocks in sports', title: 'Breaking Through Mental Blocks in Competition' },
  { keyword: 'visualization techniques athletes', title: 'Visualization Techniques That Elite Athletes Use Daily' },
  { keyword: 'ADHD athlete performance', title: 'How Athletes with ADHD Can Unlock Peak Performance' },
  { keyword: 'resilience sports psychology', title: 'Building Resilience: The Mental Skill Every Champion Needs' },
  { keyword: 'kids mental toughness', title: 'Teaching Mental Toughness to Young Athletes' }
];

const weekIndex = Math.floor(Date.now() / (7 * 86400000));
const pick = topics[weekIndex % topics.length]; // deterministic weekly rotation — no repeats until the full list cycles
const slug = pick.keyword.replace(/\s+/g, '-').toLowerCase();
const date = new Date().toISOString().split('T')[0];

return [{ json: { ...pick, slug, date } }];

